  ('fire-eq-tech-moex-02450', 'fire-eq-tech', 'fire-eq-tech-moex-100-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '依竣工查驗作業規定，進行泡沫滅火設備綜合試驗，水成膜泡沫低發泡之放射試驗，下列何者正確？', '["放射區域就預設放射壓力最高處實施", "發泡倍率應在10倍以上", "25%還原時間應在30秒以上", "泡沫稀釋濃度3%型者應在3%~4%範圍內"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "9c81e4da3013", "answer_pdf_sha1": "12f22228ebe4", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0910", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水與化學系統消防安全設備概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
